mapper.update:
UPDATE article
SET like_count = CASE id

    WHEN #{item.articleId} THEN #{item.likeCount}

END
WHERE id IN

    #{item.articleId}

update article
set view_count = view_count + 1
where id = #{articleId}

update article
set comment_count = comment_count - 1
where id = #{articleId}

mapper.select:
select a.id,a.title,a.summary,a.cover_image as coverImage, a.type,a.published_at as updatedTime,a.view_count as viewCount, a.like_count as likeCount,a.comment_count as commentCount, a.share_count as shareCount,a.collect_count as collectCount, a.share_count as shareCount, a.is_recommend as isRecommend, a.is_top as isTop, u.id as userId, u.nickname as nickName, u.avatar as avatar, c.name as categoryName, tt.tagsName as tagName, -- 计算热度得分（用于热榜排序） ( a.view_count + a.like_count * 10 + a.comment_count * 5 + a.collect_count * 3 ) / POW((TIMESTAMPDIFF(HOUR, a.published_at, NOW()) + 2),1.5) as hotScore from article a left join user u on a.user_id = u.id left join category c on a.category_id = c.id left join ( select atr.article_id, GROUP_CONCAT(at.name SEPARATOR ', ') AS tagsName from article_tag at join article_tag_relation atr on at.id = atr.tag_id group by atr.article_id ) tt on tt.article_id = a.id
where a.visibility = 0 -- 0:公开 and a.status = 1 -- 1:已发布 and a.published_at is not null -- 已发布的文章 and a.created_at >= DATE_SUB(NOW(), INTERVAL 10 DAY)
order by hotScore desc, a.published_at desc limit #{pageSize} offset #{offset}

select a.id,a.title,a.summary,a.cover_image as coverImage, a.type,a.published_at as updatedTime,a.view_count as viewCount, a.like_count as likeCount,a.comment_count as commentCount, a.share_count as shareCount,a.collect_count as collectCount, a.share_count as shareCount, a.is_recommend as isRecommend, a.is_top as isTop, u.id as userId, u.nickname as nickName, u.avatar as avatar, c.name as categoryName, tt.tagsName as tagName from article a left join user u on a.user_id = u.id left join category c on a.category_id = c.id left join ( select atr.article_id, GROUP_CONCAT(at.name SEPARATOR ', ') AS tagsName from article_tag at join article_tag_relation atr on at.id = atr.tag_id group by atr.article_id ) tt on tt.article_id = a.id
-- 关注类型接关注表 left join follow f on f.following_id = a.user_id and f.follower_id = #{request.userId}
where a.visibility = 0 -- 0:公开 and a.status = 1 -- 1:已发布 and a.published_at is not null -- 已发布的文章 and a.created_at >= DATE_SUB(NOW(), INTERVAL 10 DAY)
and f.id is not null order by a.published_at desc limit #{pageSize} offset #{offset}

