where a.visibility = 0 -- 0:公开 and a.status = 1 -- 1:已发布 and a.published_at is not null -- 已发布的文章 and a.created_at >= DATE_SUB(NOW(), INTERVAL 10 DAY)
order by a.published_at desc limit #{pageSize} offset #{offset}

select a.id, a.title, a.summary, a.cover_image as coverImage, a.type, a.published_at as updatedTime, a.view_count as viewCount, a.like_count as likeCount, a.comment_count as commentCount, a.collect_count as collectCount, a.share_count as shareCount, a.is_recommend as isRecommend, a.is_top as isTop, u.id as userId, u.nickname as nickName, u.avatar as avatar, c.name as categoryName from article a left join user u on a.user_id = u.id left join category c on a.category_id = c.id where a.visibility = 0 and a.status = 1 and a.published_at is not null
and a.id not in
#{id}
